dtsPropsFor.Button:
/** Visual style. `ai` is the violet→brand gradient used for AI actions. */
  variant?: "primary" | "secondary" | "ghost" | "danger" | "outline" | "ai";
  /** Control height. `icon` is a square icon-only button. */
  size?: "sm" | "md" | "lg" | "icon";
  /** Shows a spinner and disables interaction. */
  loading?: boolean;
  /** Leading icon element (e.g. a lucide icon). */
  icon?: React.ReactNode;
  children?: React.ReactNode;
  type?: "button" | "submit" | "reset";
  disabled?: boolean;
  onClick?: React.MouseEventHandler<HTMLButtonElement>;
  className?: string;

dtsPropsFor.Input:
type?: React.HTMLInputTypeAttribute;
  value?: string | number;
  defaultValue?: string | number;
  placeholder?: string;
  disabled?: boolean;
  required?: boolean;
  onChange?: React.ChangeEventHandler<HTMLInputElement>;
  className?: string;
  /** Accepts all native <input> attributes. */
  [attr: string]: unknown;

dtsPropsFor.Textarea:
value?: string;
  defaultValue?: string;
  placeholder?: string;
  rows?: number;
  disabled?: boolean;
  onChange?: React.ChangeEventHandler<HTMLTextAreaElement>;
  className?: string;
  /** Accepts all native <textarea> attributes. */
  [attr: string]: unknown;

dtsPropsFor.Select:
value?: string | number;
  defaultValue?: string | number;
  disabled?: boolean;
  onChange?: React.ChangeEventHandler<HTMLSelectElement>;
  /** <option> elements. */
  children?: React.ReactNode;
  className?: string;
  /** Accepts all native <select> attributes. */
  [attr: string]: unknown;

dtsPropsFor.Field:
/** Label rendered above the control. */
  label?: string;
  /** Helper text rendered below the control. */
  hint?: string;
  /** Appends a red asterisk to the label. */
  required?: boolean;
  children: React.ReactNode;
  className?: string;

dtsPropsFor.CardHeader:
title: React.ReactNode;
  subtitle?: React.ReactNode;
  /** Right-aligned actions (buttons, badges). */
  actions?: React.ReactNode;

dtsPropsFor.CheckboxItem:
checked: boolean;
  onChange: (value: boolean) => void;
  label: string;
  /** Optional clinical-definition tooltip shown beside the label. */
  tooltip?: string;
  disabled?: boolean;

dtsPropsFor.Modal:
/** Controls visibility; returns null when false. */
  open: boolean;
  /** Called on backdrop click or the close (X) button. */
  onClose: () => void;
  title?: React.ReactNode;
  children: React.ReactNode;
  /** Max-width preset. */
  size?: "sm" | "md" | "lg" | "xl";

dtsPropsFor.EmptyState:
icon?: React.ReactNode;
  title: string;
  description?: string;
  /** Call-to-action element (usually a Button). */
  action?: React.ReactNode;

dtsPropsFor.AiAssistButton:
/** Button label. */
  label: string;
  /** Builds the AI completion request payload when clicked. */
  request: () => Record<string, unknown>;
  /** Receives the generated text. */
  onResult: (text: string) => void;
  size?: "sm" | "md";
  variant?: "ai" | "secondary" | "outline";

dtsPropsFor.TranscribeButton:
/** Receives transcribed text (callers append it to the current value). */
  onTranscript: (text: string) => void;
  label?: string;
  size?: "sm" | "md";

dtsPropsFor.ConfirmDialog:
open: boolean;
  onClose: () => void;
  onConfirm: () => void;
  title: string;
  message: React.ReactNode;
  confirmLabel?: string;
  /** Styles the confirm action as destructive (red). */
  danger?: boolean;
  loading?: boolean;

dtsPropsFor.StepShell:
title: string;
  description?: React.ReactNode;
  /** Right-aligned header actions. */
  actions?: React.ReactNode;
  children: React.ReactNode;

dtsPropsFor.EpisodeTimeline:
/** Encounters of the care episode, chronological. */
  exams: Array<{ id: string; tipo?: string; seq?: number; createdAt?: string; lockedAt?: string | null; data?: Record<string, unknown> }>;
  /** Compact side-rail vs. full document layout. */
  variant?: "rail" | "document";
  /** Extra trailing nodes (e.g. "discharge in progress"). */
  children?: React.ReactNode;
